import { Link } from 'react-router-dom';

export default function ModelCard({ model }) {
  return (
    <Link to={`/models/${model.id}`} style={{ textDecoration: 'none' }}>
      <div style={{ padding: '18px', borderRadius: '18px', background: 'rgba(30,41,59,0.6)', color: '#fff', transition: '0.3s', position: 'relative' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
          <h3>{model.name}</h3>
          <span style={{ fontSize: '12px', background: '#38bdf8', padding: '4px 8px', borderRadius: '6px' }}>{model.type}</span>
        </div>
        <p style={{ marginTop: '10px', opacity: 0.7 }}>{model.description}</p>
      </div>
    </Link>
  );
}
